    88→	async findTopCopurchasesDiversified({
    89→		styleId,
    90→		limit = 4,
    91→		excludeIds = [],
    92→		diversifyCategories = false,
    93→		favorOppositeType = false,
    94→		seedStyleType,
    95→	}: {
    96→		styleId: number;
    97→		limit?: number;
    98→		excludeIds?: number[];
    99→		diversifyCategories?: boolean;
   100→		favorOppositeType?: boolean;
   101→		seedStyleType?: string | null | undefined;
   102→	}): Promise<
   103→		{
   104→			paired_style_id: number;
   105→			copurchase_count: number;
   106→			primary_category_id: number;
   107→			style_type: string | null;
   108→		}[]
   109→	> {
   110→		const dto = plainToInstance(FindTopCopurchasesDiversifiedDto, {
   111→			styleId,
   112→			limit,
   113→			excludeIds,
   114→			diversifyCategories,
   115→			favorOppositeType,
   116→			seedStyleType,
   117→		});
   118→		const errors = await validate(dto);
   119→		if (errors.length > 0) {
   120→			throw new Error(`Validation failed: ${this.formatValidationErrors(errors)}`);
   121→		}
   122→
   123→		try {
   124→			const queryA = this.knexRead(this.tableName)
   125→				.select('style_id_b as paired_style_id', 'copurchase_count')
   126→				.where({ style_id_a: styleId })
   127→				.whereNull('deleted_at');
   128→
   129→			const queryB = this.knexRead(this.tableName)
   130→				.select('style_id_a as paired_style_id', 'copurchase_count')
   131→				.where({ style_id_b: styleId })
   132→				.whereNull('deleted_at');
   133→
   134→			if (excludeIds.length > 0) {
   135→				queryA.whereNotIn('style_id_b', excludeIds);
   136→				queryB.whereNotIn('style_id_a', excludeIds);
   137→			}
   138→
   139→			const pairsSubquery = this.knexRead.unionAll([queryA, queryB]).as('pairs');
   140→
   141→			const baseQuery = this.knexRead
   142→				.select(
   143→					'pairs.paired_style_id',
   144→					'pairs.copurchase_count',
   145→					'mv.primary_category_id',
   146→					'mv.style_type',
   147→				)
   148→				.from(pairsSubquery)
   149→				.join(TABLE_NAME_STYLES_MV + ' as mv', function () {
   150→					this.on('mv.style_id', '=', 'pairs.paired_style_id').andOnNull('mv.deleted_at');
   151→				});
   152→
   153→			let query: Knex.QueryBuilder;
   154→
   155→			if (diversifyCategories) {
   156→				query = this.knexRead
   157→					.with(
   158→						'copurchases',
   159→						baseQuery
   160→							.clone()
   161→							.select(
   162→								this.knexRead.raw(
   163→									'ROW_NUMBER() OVER (PARTITION BY mv.primary_category_id ORDER BY pairs.copurchase_count DESC) AS rn',
   164→								),
   165→							),
   166→					)
   167→					.select(
   168→						'paired_style_id',
   169→						'copurchase_count',
   170→						'primary_category_id',
   171→						'style_type',
   172→					)
   173→					.from('copurchases')
   174→					.where('rn', 1);
   175→			} else {
   176→				query = baseQuery;
   177→			}
   178→
   179→			if (favorOppositeType) {
   180→				if (seedStyleType) {
   181→					query.orderByRaw('CASE WHEN style_type != ? THEN 0 ELSE 1 END', [
   182→						seedStyleType,
   183→					]);
   184→				} else {
   185→					query.orderByRaw('CASE WHEN style_type IS NOT NULL THEN 0 ELSE 1 END');
   186→				}
   187→			}
   188→
   189→			query.orderBy('copurchase_count', 'desc').limit(limit);
   190→
   191→			const results = (await query) as ICopurchaseRow[];
   192→
   193→			this.logger.debug(
   194→				`Found ${results.length} diversified copurchases for style ${styleId}`,
   195→			);
   196→
   197→			return results.map((row: ICopurchaseRow) => ({
   198→				paired_style_id: Number(row.paired_style_id),
   199→				copurchase_count: Number(row.copurchase_count),
   200→				primary_category_id: Number(row.primary_category_id),
   201→				style_type: row.style_type,
   202→			}));
   203→		} catch (error: unknown) {
   204→			const err = error instanceof Error ? error : new Error(String(error));
   205→			this.logger.error(
   206→				`Failed to find diversified copurchases for style ${styleId}: ${err.message}`,
   207→			);
   208→			throw err;
   209→		}
   210→	}
